def factorial(n: int) -> int:
    if n <= 1:                     # base case
        return 1
    return n * factorial(n - 1)    # recursive case (smaller n)

print(factorial(5))   # 120

def walk(node):
    if node is None: return
    yield node.value
    for child in node.children:
        yield from walk(child)

# `yield from walk(child)` keeps the recursion natural while producing a flat stream of values.

from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n: int) -> int:
    if n < 2: return n
    return fib(n - 1) + fib(n - 2)

print(fib(60))   # instant
# Without lru_cache, fib(60) is ~10^12 calls.

# Recursive (will RecursionError for large n):
def sum_to(n, acc=0):
    if n == 0: return acc
    return sum_to(n - 1, acc + n)

# Iterative equivalent — same algorithm, no stack growth:
def sum_to_iter(n):
    acc = 0
    while n:
        acc += n
        n -= 1
    return acc
